#this script is to pull module colors from WGCNA output and plot their expression
#Danielle Jordan

#Load libraries 
library(WGCNA)
library(flashClust)
library(edgeR)
library(tidyverse)
library(dplyr)
library(ggplot2)
library(sva)
library(statmod)
library(Dict)
