#Read in Camilo's annotations file 
cam_ann <- read.csv("camilo_ann.csv", stringsAsFactors = FALSE, header = TRUE, sep = ",")

# Define a function to rename gene names
rename_genes <- function(df) {
  # Define a regular expression to match the pattern (period and text after it)
  pattern <- "\\..*"
  
  # Loop through each gene name in the "genes" column and rename it
  df$genes <- gsub(pattern, "", df$genes)
  
  return(df)
}

# Rename genes in the dataframe "cam_ann"
cam_ann <- rename_genes(cam_ann)
cam_ann <- cam_ann[,-1]

#Filter for red file since this is the trickiest 
cam_red <- filter(cam_ann, cam_ann$genes %in% red$genes)
write.csv(cam_red, "cam_red.csv")

#Filter for magenta
cam_mag <- filter(cam_ann, cam_ann$genes %in% magenta$genes )
write.csv(cam_mag, "cam_mag.csv")

#Filter for pink
cam_pink <- filter(cam_ann, cam_ann$genes %in% pink$genes )
write.csv(cam_mag, "cam_pink.csv")

#Filter for green
